<?php
namespace App\Models;
use App\Core\Model;
class DashboardModel extends Model { public function stats():array{return ['cables'=>$this->fetch('SELECT COUNT(*) c FROM cables WHERE deleted_at IS NULL')['c']??0,'reparacion'=>$this->fetch("SELECT COUNT(*) c FROM cables WHERE estado='en reparación' AND deleted_at IS NULL")['c']??0,'informes_hoy'=>$this->fetch('SELECT COUNT(*) c FROM informes_cable WHERE DATE(created_at)=CURDATE()')['c']??0,'stock_bajo'=>$this->fetch('SELECT COUNT(*) c FROM materiales WHERE stock_actual<=stock_minimo AND deleted_at IS NULL')['c']??0,'ult_entregas'=>$this->fetchAll('SELECT e.*, CONCAT(u.nombre," ",u.apellido) receptor FROM entregas_materiales e JOIN usuarios u ON u.id=e.usuario_receptor_id ORDER BY e.id DESC LIMIT 5'),'ult_informes'=>$this->fetchAll('SELECT i.*, c.numero_cable FROM informes_cable i JOIN cables c ON c.id=i.cable_id ORDER BY i.id DESC LIMIT 5'),'cable_estados'=>$this->fetchAll('SELECT estado,COUNT(*) total FROM cables WHERE deleted_at IS NULL GROUP BY estado'),'mat_usados'=>$this->fetchAll('SELECT m.nombre_material, SUM(im.cantidad_utilizada) total FROM informe_materiales im JOIN materiales m ON m.id=im.material_id GROUP BY m.id ORDER BY total DESC LIMIT 6')];}}
